import { Injectable } from '@angular/core';
import { StockColor, StockItem } from '../models/stock-item';

@Injectable({
  providedIn: 'root'
})
export class StockStorageService {
  private readonly storageKey = 'spa-stock-v1';

  async getAll(): Promise<StockItem[]> {
    const raw = localStorage.getItem(this.storageKey);
    if (!raw) return [];

    try {
      const parsed = JSON.parse(raw) as StockItem[];
      return Array.isArray(parsed) ? parsed : [];
    } catch {
      return [];
    }
  }

  async saveAll(items: StockItem[]): Promise<void> {
    localStorage.setItem(this.storageKey, JSON.stringify(items));
  }

  async ensureSeed(): Promise<void> {
    const existing = await this.getAll();
    if (existing.length > 0) return;

    const seed = this.createSeed();
    await this.saveAll(seed);
  }

  private createSeed(): StockItem[] {
    const specs: Array<{ category: string; prefix: string; count: number; unit: string }> = [
      { category: 'Profiles Serie 40', prefix: 'S40-PROFILE', count: 22, unit: 'm' },
      { category: 'Accessoires Serie 40', prefix: 'S40-ACCESS', count: 18, unit: 'pcs' },
      { category: 'Joints Serie 40', prefix: 'S40-JOINT', count: 5, unit: 'm' },
      { category: 'Profiles Serie 67', prefix: 'S67-PROFILE', count: 9, unit: 'm' },
      { category: 'Accessoires Serie 67', prefix: 'S67-ACCESS', count: 9, unit: 'pcs' },
      { category: 'Joints Serie 67', prefix: 'S67-JOINT', count: 4, unit: 'm' },
      { category: 'Accessoires Porte Securite', prefix: 'PSEC-ACCESS', count: 9, unit: 'pcs' }
    ];

    const colors: StockColor[] = ['blanc', 'gris', 'noir'];
    const items: StockItem[] = [];
    let index = 0;

    specs.forEach((spec) => {
      for (let i = 1; i <= spec.count; i += 1) {
        const color = colors[index % colors.length];
        index += 1;
        items.push({
          id: this.createId(),
          reference: `${spec.prefix}-${String(i).padStart(2, '0')}`,
          category: spec.category,
          color,
          photoUrl: 'assets/stock/placeholder.png',
          unit: spec.unit,
          quantity: 0,
          lowStockThreshold: 5,
          lastUpdated: new Date().toISOString()
        });
      }
    });

    return items;
  }

  private createId(): string {
    return globalThis.crypto?.randomUUID?.() ??
      `stock_${Date.now()}_${Math.random().toString(16).slice(2)}`;
  }
}
